(window.webpackJsonp=window.webpackJsonp||[]).push([[75],{702:function(n,r){n.exports="\x3c!-- \r\ntitle: 11-Linux常用指令\r\nsort: \r\n--\x3e \r\n# linux常用指令\r\n\r\n## 建立链接\r\n\r\n- 软链接（快捷方式）\r\n  - ln -s\r\n- 硬链接（多个名字）\r\n  - ln\r\n\r\n##  文件搜索\r\n\r\n+ 在文本内部搜索（grep）\r\n\r\n  > grep “内容” 文件路径\r\n  >\r\n  > -n\t  查看行数\r\n  >\r\n  > -i\t\t忽略大小写\r\n  >\r\n  > -v\t\t取反\r\n\r\n+ 在计算机内搜索文件（find）\r\n\r\n  > find 目标目录 选项 条件 \r\n  >\r\n  > -name\t按名称\r\n  >\r\n  > -size\t\t按大小\r\n  >\r\n  > > +32M\t大于32M\r\n  > >\r\n  > > -15M\t小于15M\r\n\r\n## 归档和压缩\r\n\r\n- 归档和解档\r\n  \r\n  > -cvf\r\n  >\r\n  > -xvf\r\n  \r\n- 压缩和解压\r\n  \r\n  > -zcvf\r\n  >\r\n  > -zxvf\r\n  >\r\n  \r\n- zip压缩及解压\r\n  > zip -r 文件名 源文件名\r\n  >\r\n  > unzip 文件名\r\n## 文件权限\r\n\r\n```BASH\r\nchmod [-cfvR] [--help] [--version] [ugoa...][[+-=][rwxX]\r\n```\r\n\r\n- 权限修改（chmod）\r\n\r\n  > -Rv：显示详细信息与设置\r\n  >\r\n  > 用户：u g o a\r\n  >\r\n  > 权限设置：+ - =\r\n  >\r\n  > 用法：chmod a=rwx\r\n  >\r\n  > rwx：421\r\n  >\r\n  > chmod 777\t最高权限\r\n  >\r\n  > chmod -R 755 目录\t递归分配权限\r\n\r\n## 用户管理\r\n\r\n- sudo -s\t切换用户\r\n\r\n- passwd    修改密码\r\n\r\n- who         切换用户\r\n\r\n- 关机\r\n\r\n  > shutdown -c\t取消关机\r\n  >\r\n  > shutdown now\t现在关机\r\n  >\r\n  > shudown -r now\t重启\r\n  >\r\n  > shutdown +20\t20分钟后关机\r\n\r\n## 远程操作\r\n\r\n+ ssh\t远程连接\r\n\r\n+ scp    远程拷贝\r\n\r\n  > scp 源文件目录 目标文件目录\r\n\r\n## vim的使用\r\n\r\n+ 进入输入模式\r\n\r\n  > i\t光标前插入\r\n  >\r\n  > I\t行首插入\r\n  >\r\n  > a\t光标后插入\r\n  >\r\n  > A\t行末插入\r\n  >\r\n  > o\t向下产生新行\r\n  >\r\n  > O\t向上产生新行\r\n\r\n+ 命令模式\r\n\r\n  > h、l\t向左、右移动\r\n  >\r\n  > j、k\t向下、上移动\r\n  >\r\n  > H、M、L\t返回开头、中间、末尾\r\n  >\r\n  > g\t\t回到最后一行\r\n  >\r\n  > u、Ctrl+r\t\t撤回/反撤回\r\n  >\r\n  > dd \t\t删除一行\r\n  >\r\n  > n dd\t\t删除多行\r\n  >\r\n  > D、d0\t删除光标前、光标后全部内容\r\n  >\r\n  > x、X\t\t删除光标所在字符、前一个\r\n  >\r\n  >  .\t\t重复指令\r\n  >\r\n  > n yy、p\t复制、粘贴\r\n  >\r\n  > r、R\t\t替换字符\r\n  >\r\n  > :%s/目标/替换/g\t批量替换字符\r\n  >\r\n  > /目标\t\t查找内容\r\n\r\n"}}]);